pub(crate) fn try_build_exact_zero_identity_rewrite(
    ctx: &mut cas_ast::Context,
    expr: cas_ast::ExprId,
) -> Option<Rewrite> {
    if let Some((lhs_core, rhs_core)) = extract_two_term_core_difference(ctx, expr) {
        if is_atanh_common_log_definition_mismatch_pair(ctx, lhs_core, rhs_core) {
            return None;
        }
    }

    if let Some(rewrite) = try_build_exact_zero_identity_rewrite_direct(ctx, expr) {
        return Some(rewrite);
    }

    let view = AddView::from_expr(ctx, expr);
    if !(2..=4).contains(&view.terms.len()) {
        return None;
    }

    let flipped_terms: Vec<_> = view
        .terms
        .iter()
        .map(|(term_expr, term_sign)| (*term_expr, term_sign.negate()))
        .collect();
    let flipped_expr = build_signed_sum_expr(ctx, &flipped_terms);
    let child_rewrite = try_build_exact_zero_identity_rewrite_direct(ctx, flipped_expr)?;

    let mut rewrite = Rewrite::with_local(
        ctx.num(0),
        child_rewrite.description.clone(),
        expr,
        ctx.num(0),
    )
    .requires_all(child_rewrite.required_conditions.clone())
    .assume_all(child_rewrite.assumption_events.clone());

    if let Some(poly_proof) = child_rewrite.poly_proof.clone() {
        rewrite = rewrite.poly_proof(poly_proof);
    }

    rewrite.substeps = child_rewrite.substeps.clone();
    Some(rewrite)
}

fn build_mul_expr_from_factors(
    ctx: &mut cas_ast::Context,
    factors: &[cas_ast::ExprId],
) -> cas_ast::ExprId {
    match factors {
        [] => ctx.num(1),
        [single] => *single,
        _ => build_balanced_mul(ctx, factors),
    }
}

fn strip_common_factor_from_term(
    ctx: &mut cas_ast::Context,
    term_expr: cas_ast::ExprId,
    common_factor: cas_ast::ExprId,
) -> Option<cas_ast::ExprId> {
    let term_factors = flatten_mul_chain(ctx, term_expr);
    let common_factors = flatten_mul_chain(ctx, common_factor);
    if term_factors.is_empty() || common_factors.is_empty() {
        return None;
    }

    let mut used = vec![false; term_factors.len()];
    for common in common_factors {
        let matched_index = term_factors
            .iter()
            .enumerate()
            .find_map(|(index, factor)| {
                (!used[index] && compare_expr(ctx, *factor, common) == Ordering::Equal)
                    .then_some(index)
            })?;
        used[matched_index] = true;
    }

    let residual_factors: Vec<_> = term_factors
        .into_iter()
        .enumerate()
        .filter_map(|(index, factor)| (!used[index]).then_some(factor))
        .collect();
    Some(build_mul_expr_from_factors(ctx, &residual_factors))
}

fn extract_two_term_common_scale_difference_cores(
    ctx: &mut cas_ast::Context,
    expr: cas_ast::ExprId,
) -> Option<(cas_ast::ExprId, cas_ast::ExprId, cas_ast::ExprId)> {
    let view = AddView::from_expr(ctx, expr);
    if view.terms.len() != 2 {
        return None;
    }

    let (common_factor, _) = extract_common_multiplicative_residual_sum(ctx, expr)?;
    let lhs_residual = strip_common_factor_from_term(ctx, view.terms[0].0, common_factor)?;
    let rhs_residual = strip_common_factor_from_term(ctx, view.terms[1].0, common_factor)?;
    let lhs_core = apply_sign_to_expr(ctx, sign_to_i64(view.terms[0].1), lhs_residual);
    let rhs_core = apply_sign_to_expr(
        ctx,
        sign_to_i64(view.terms[1].1).checked_neg()?,
        rhs_residual,
    );
    Some((common_factor, lhs_core, rhs_core))
}

fn extract_common_multiplicative_residual_sum(
    ctx: &mut cas_ast::Context,
    expr: cas_ast::ExprId,
) -> Option<(cas_ast::ExprId, cas_ast::ExprId)> {
    let view = AddView::from_expr(ctx, expr);
    if view.terms.len() < 2 {
        return None;
    }

    let normalized_terms: Vec<_> = view
        .terms
        .iter()
        .copied()
        .map(|(term_expr, term_sign)| normalize_signed_add_term(ctx, term_expr, term_sign))
        .collect();

    let first_factors = flatten_mul_chain(ctx, normalized_terms.first()?.0);
    if first_factors.is_empty() {
        return None;
    }

    let mut used_by_term: Vec<Vec<bool>> = normalized_terms
        .iter()
        .map(|(term_expr, _)| vec![false; flatten_mul_chain(ctx, *term_expr).len()])
        .collect();
    let factor_lists: Vec<Vec<_>> = normalized_terms
        .iter()
        .map(|(term_expr, _)| flatten_mul_chain(ctx, *term_expr))
        .collect();

    let mut common = Vec::new();
    for first_factor in first_factors {
        let mut matched_indexes = Vec::new();
        let mut all_match = true;

        for (term_index, factors) in factor_lists.iter().enumerate().skip(1) {
            let Some(factor_index) =
                factors
                    .iter()
                    .enumerate()
                    .find_map(|(factor_index, factor)| {
                        (!used_by_term[term_index][factor_index]
                            && compare_expr(ctx, *factor, first_factor) == Ordering::Equal)
                            .then_some(factor_index)
                    })
            else {
                all_match = false;
                break;
            };
            matched_indexes.push((term_index, factor_index));
        }

        if !all_match {
            continue;
        }

        common.push(first_factor);
        for (term_index, factor_index) in matched_indexes {
            used_by_term[term_index][factor_index] = true;
        }

        if let Some(first_index) =
            factor_lists[0]
                .iter()
                .enumerate()
                .find_map(|(factor_index, factor)| {
                    (!used_by_term[0][factor_index]
                        && compare_expr(ctx, *factor, first_factor) == Ordering::Equal)
                        .then_some(factor_index)
                })
        {
            used_by_term[0][first_index] = true;
        }
    }

    if common.is_empty() {
        return None;
    }

    let residual_terms: Vec<_> = normalized_terms
        .iter()
        .enumerate()
        .map(|(term_index, (_term_expr, term_sign))| {
            let residual_factors: Vec<_> = factor_lists[term_index]
                .iter()
                .copied()
                .enumerate()
                .filter_map(|(factor_index, factor)| {
                    (!used_by_term[term_index][factor_index]).then_some(factor)
                })
                .collect();
            (
                build_mul_expr_from_factors(ctx, &residual_factors),
                *term_sign,
            )
        })
        .collect();

    let common_factor = build_mul_expr_from_factors(ctx, &common);
    let residual_expr = build_signed_sum_expr(ctx, &residual_terms);
    let one = ctx.num(1);
    if compare_expr(ctx, common_factor, one) == Ordering::Equal
        || compare_expr(ctx, residual_expr, expr) == Ordering::Equal
    {
        return None;
    }
    Some((common_factor, residual_expr))
}

fn build_common_scale_exact_zero_rewrite(
    ctx: &mut cas_ast::Context,
    whole_expr: cas_ast::ExprId,
    common_factor: cas_ast::ExprId,
    residual_expr: cas_ast::ExprId,
    child_rewrite: Rewrite,
) -> Rewrite {
    let factorized_difference = smart_mul(ctx, common_factor, residual_expr);
    let factorized_display = format!(
        "{}",
        cas_formatter::DisplayExpr {
            context: ctx,
            id: factorized_difference
        }
    );

    let mut rewrite = Rewrite::with_local(
        ctx.num(0),
        child_rewrite.description.clone(),
        whole_expr,
        ctx.num(0),
    )
    .requires_all(child_rewrite.required_conditions.clone())
    .assume_all(child_rewrite.assumption_events.clone());

    if let Some(poly_proof) = child_rewrite.poly_proof.clone() {
        rewrite = rewrite.poly_proof(poly_proof);
    }

    rewrite = rewrite.substep(
        "Sacar factor común",
        vec![format!("Se obtiene {factorized_display}.")],
    );
    rewrite.substeps.extend(child_rewrite.substeps.clone());
    rewrite
}

fn positive_assumption_subject_for_abs_like_expr(
    ctx: &mut cas_ast::Context,
    expr: cas_ast::ExprId,
) -> Option<cas_ast::ExprId> {
    if let Some(inner) = abs_argument(ctx, expr) {
        return Some(inner);
    }

    let radicand = extract_square_root_base(ctx, expr)?;
    match ctx.get(radicand).clone() {
        Expr::Pow(base, exponent) if extract_i64_integer(ctx, exponent) == Some(2) => Some(base),
        Expr::Mul(lhs, rhs) if exprs_match_for_cancellation(ctx, lhs, rhs) => Some(lhs),
        _ => None,
    }
}

fn positive_assumption_subject_for_abs_like_core_pair(
    ctx: &mut cas_ast::Context,
    lhs_core: cas_ast::ExprId,
    rhs_core: cas_ast::ExprId,
) -> Option<cas_ast::ExprId> {
    if let Some(subject) = positive_assumption_subject_for_abs_like_expr(ctx, lhs_core) {
        if exprs_match_for_cancellation(ctx, subject, rhs_core) {
            return Some(subject);
        }
    }

    if let Some(subject) = positive_assumption_subject_for_abs_like_expr(ctx, rhs_core) {
        if exprs_match_for_cancellation(ctx, subject, lhs_core) {
            return Some(subject);
        }
    }

    None
}

pub(crate) fn common_scale_abs_like_positive_assumption_event(
    ctx: &mut cas_ast::Context,
    expr: cas_ast::ExprId,
    parent_ctx: &ParentContext,
) -> Option<crate::AssumptionEvent> {
    if !matches!(parent_ctx.domain_mode(), crate::DomainMode::Assume) {
        return None;
    }

    let (_common_factor, lhs_core, rhs_core) =
        extract_two_term_common_scale_difference_cores(ctx, expr)?;
    let subject = positive_assumption_subject_for_abs_like_core_pair(ctx, lhs_core, rhs_core)?;
    if crate::helpers::prove_positive(ctx, subject, parent_ctx.value_domain())
        == crate::Proof::Proven
    {
        return None;
    }

    Some(crate::AssumptionEvent::positive_assumed(ctx, subject))
}

fn try_build_exact_zero_common_scaled_difference_rewrite_with_context(
    ctx: &mut cas_ast::Context,
    expr: cas_ast::ExprId,
    parent_ctx: &ParentContext,
) -> Option<Rewrite> {
    let mut rewrite = try_build_exact_zero_common_scaled_difference_rewrite(ctx, expr)?;
    if rewrite.assumption_events.is_empty() {
        if let Some(event) = common_scale_abs_like_positive_assumption_event(ctx, expr, parent_ctx)
        {
            rewrite = rewrite.assume(event);
        }
    }
    Some(rewrite)
}

fn strip_single_additive_zero_term(
    ctx: &mut cas_ast::Context,
    expr: cas_ast::ExprId,
) -> Option<cas_ast::ExprId> {
    let terms = AddView::from_expr(ctx, expr).terms;
    if terms.len() < 2 {
        return None;
    }

    let zero = ctx.num(0);
    let mut removed = false;
    let mut remaining = Vec::with_capacity(terms.len().saturating_sub(1));
    for (term_expr, term_sign) in terms {
        if !removed && compare_expr(ctx, term_expr, zero) == Ordering::Equal {
            removed = true;
            continue;
        }
        remaining.push((term_expr, term_sign));
    }

    if !removed || remaining.is_empty() {
        return None;
    }

    Some(build_signed_sum_expr(ctx, &remaining))
}

fn additive_scope_contains_zero_term(ctx: &mut cas_ast::Context, expr: cas_ast::ExprId) -> bool {
    let terms = AddView::from_expr(ctx, expr).terms;
    if terms.len() < 2 {
        return false;
    }

    let zero = ctx.num(0);
    terms
        .into_iter()
        .any(|(term_expr, _term_sign)| compare_expr(ctx, term_expr, zero) == Ordering::Equal)
}

fn try_build_stripped_zero_log_identity_child_rewrite(
    ctx: &mut cas_ast::Context,
    residual_expr: cas_ast::ExprId,
) -> Option<Rewrite> {
    let stripped_residual = strip_single_additive_zero_term(ctx, residual_expr)?;
    if !expr_contains_any_builtin(
        ctx,
        stripped_residual,
        &[
            BuiltinFn::Ln,
            BuiltinFn::Log,
            BuiltinFn::Log2,
            BuiltinFn::Log10,
            BuiltinFn::Abs,
        ],
    ) {
        return None;
    }

    let child_rewrite = try_build_exact_zero_identity_rewrite(ctx, stripped_residual)?;
    let zero = ctx.num(0);
    (compare_expr(ctx, child_rewrite.final_expr(), zero) == Ordering::Equal)
        .then_some(child_rewrite)
}

fn try_find_exact_zero_additive_factor_in_product(
    ctx: &mut cas_ast::Context,
    expr: cas_ast::ExprId,
) -> Option<(cas_ast::ExprId, Rewrite)> {
    let factors = flatten_mul_chain(ctx, expr);
    if factors.len() < 2 {
        return None;
    }

    for factor in factors {
        if !matches!(ctx.get(factor), Expr::Add(_, _) | Expr::Sub(_, _)) {
            continue;
        }
        if let Some((lhs_core, rhs_core)) = extract_two_term_core_difference(ctx, factor) {
            if is_atanh_common_log_definition_mismatch_pair(ctx, lhs_core, rhs_core) {
                continue;
            }
            if expr_contains_sqrt_or_half_power(ctx, factor) {
                if let Some(child_rewrite) =
                    try_build_direct_scaled_reciprocal_half_power_product_rewrite(
                        ctx, lhs_core, rhs_core,
                    )
                {
                    return Some((factor, child_rewrite));
                }
            }
        }

        if let Some(child_rewrite) = try_build_small_direct_zero_core_rewrite(ctx, factor) {
            return Some((factor, child_rewrite));
        }
        let child_rewrite = try_build_exact_zero_identity_rewrite(ctx, factor)?;
        return Some((factor, child_rewrite));
    }

    None
}

fn try_build_exact_zero_identity_rewrite_direct(
    ctx: &mut cas_ast::Context,
    expr: cas_ast::ExprId,
) -> Option<Rewrite> {
    try_build_exact_zero_identity_rewrite_direct_impl(ctx, expr, true)
}

fn build_exact_zero_product_factor_rewrite(
    ctx: &mut cas_ast::Context,
    local_factor: cas_ast::ExprId,
    child_rewrite: Rewrite,
) -> Rewrite {
    let mut rewrite = Rewrite::with_local(
        ctx.num(0),
        child_rewrite.description.clone(),
        local_factor,
        ctx.num(0),
    )
    .requires_all(child_rewrite.required_conditions.clone())
    .assume_all(child_rewrite.assumption_events.clone());

    if let Some(poly_proof) = child_rewrite.poly_proof.clone() {
        rewrite = rewrite.poly_proof(poly_proof);
    }

    rewrite.substeps = child_rewrite.substeps.clone();
    rewrite
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub(crate) enum ExactZeroCommonScaleRouteProfileFamily {
    SameDenominator,
    ResidualDirect,
    TailFastTrigRaw,
    TailFastTrigNormalized,
    TailTwoTermCoreEquivalence,
    Other,
}

pub(crate) fn classify_exact_zero_common_scale_route_profile_family(
    ctx: &mut cas_ast::Context,
    expr: cas_ast::ExprId,
) -> Option<ExactZeroCommonScaleRouteProfileFamily> {
    if try_build_exact_zero_same_denominator_rewrite(ctx, expr).is_some() {
        return Some(ExactZeroCommonScaleRouteProfileFamily::SameDenominator);
    }

    if let Some((common_factor, lhs_core, rhs_core)) =
        extract_two_term_common_scale_difference_cores(ctx, expr)
    {
        let residual_expr = ctx.add(Expr::Sub(lhs_core, rhs_core));
        if try_build_repeated_trig_phase_shift_pair_zero_rewrite(ctx, residual_expr).is_some()
            || try_build_exact_zero_shared_passthrough_difference_rewrite(ctx, residual_expr)
                .is_some()
            || try_build_direct_tanh_exp_definition_equivalence_rewrite(ctx, lhs_core, rhs_core)
                .is_some()
            || try_build_direct_trig_square_equivalence_rewrite(ctx, lhs_core, rhs_core).is_some()
            || try_build_direct_hyperbolic_sinh_cubic_polynomial_equivalence_rewrite(
                ctx, lhs_core, rhs_core,
            )
            .is_some()
            || try_build_direct_trig_exact_quarter_phase_shift_pair_equivalence_rewrite(
                ctx, lhs_core, rhs_core,
            )
            .is_some()
            || try_build_direct_safe_hyperbolic_core_equivalence_rewrite(ctx, lhs_core, rhs_core)
                .is_some()
        {
            let _ = common_factor;
            return Some(ExactZeroCommonScaleRouteProfileFamily::Other);
        }
    }

    let (_common_factor, residual_expr) = extract_common_multiplicative_residual_sum(ctx, expr)?;
    let residual_term_count = AddView::from_expr(ctx, residual_expr).terms.len();
    if residual_term_count == 2 {
        if let Some((lhs_core, rhs_core)) = extract_two_term_core_difference(ctx, residual_expr) {
            if try_build_direct_core_equivalence_rewrite(ctx, lhs_core, rhs_core).is_some() {
                return Some(ExactZeroCommonScaleRouteProfileFamily::ResidualDirect);
            }
        }
    }
    if try_build_repeated_trig_phase_shift_pair_zero_rewrite(ctx, residual_expr).is_some()
        || try_build_exact_zero_shared_passthrough_difference_rewrite(ctx, residual_expr).is_some()
        || (residual_term_count <= 4
            && try_build_exact_zero_identity_rewrite_direct(ctx, residual_expr).is_some_and(
                |child_rewrite| {
                    let zero = ctx.num(0);
                    compare_expr(ctx, child_rewrite.final_expr(), zero) == Ordering::Equal
                },
            ))
        || try_build_stripped_zero_log_identity_child_rewrite(ctx, residual_expr)
            .or_else(|| {
                try_build_fast_multiterm_hyperbolic_residual_child_rewrite(ctx, residual_expr)
            })
            .is_some()
        || extract_two_term_core_difference(ctx, residual_expr).is_some_and(
            |(lhs_core, rhs_core)| {
                try_build_direct_safe_hyperbolic_core_equivalence_rewrite(ctx, lhs_core, rhs_core)
                    .is_some()
            },
        )
    {
        return Some(ExactZeroCommonScaleRouteProfileFamily::Other);
    }

    let normalized_residual = normalize_additive_scope_expr(ctx, residual_expr);
    if try_build_fast_trig_residual_identity_child_rewrite(ctx, residual_expr).is_some() {
        return Some(ExactZeroCommonScaleRouteProfileFamily::TailFastTrigRaw);
    }
    if try_build_fast_trig_residual_identity_child_rewrite(ctx, normalized_residual).is_some() {
        return Some(ExactZeroCommonScaleRouteProfileFamily::TailFastTrigNormalized);
    }
    if try_build_exact_zero_shared_passthrough_difference_rewrite(ctx, residual_expr).is_some()
        || try_build_fast_small_polynomial_residual_child_rewrite(ctx, residual_expr).is_some()
        || try_build_fast_small_polynomial_residual_child_rewrite(ctx, normalized_residual)
            .is_some()
    {
        return Some(ExactZeroCommonScaleRouteProfileFamily::Other);
    }
    if try_build_two_term_core_equivalence_rewrite(ctx, residual_expr).is_some() {
        return Some(ExactZeroCommonScaleRouteProfileFamily::TailTwoTermCoreEquivalence);
    }
    if try_build_exact_zero_identity_rewrite(ctx, residual_expr).is_some()
        || try_build_exact_zero_identity_rewrite(ctx, normalized_residual).is_some()
    {
        return Some(ExactZeroCommonScaleRouteProfileFamily::Other);
    }

    None
}

/// EXACT soundness witness for the "collapse to 0" routes: if `expr` is a rational/algebraic form
/// whose value at a generic rational assignment of its free variables is provably NON-ZERO, then it
/// is NOT identically zero and must never be collapsed to `0`. Returns `true` on such a witness.
/// Transcendental sub-terms (`sin`, `exp`, surds …) make `as_rational_const` return `None`, so those
/// routes keep their existing behaviour — this guard only ever VETOES a wrong collapse, never forces
/// one. Catches e.g. `1/(x²−1) − 1/(x−1)` (value −2/3 at x=2), which a pattern matcher mistook for a
/// common-scale cancellation.
/// Exact rational evaluation of a constant expression, including INTEGER powers (which
/// `as_rational_const` declines). `None` for any transcendental/non-rational sub-term, a division by
/// zero, or a non-integer / oversized exponent.
fn eval_exact_rational(
    ctx: &cas_ast::Context,
    expr: cas_ast::ExprId,
    depth: usize,
) -> Option<num_rational::BigRational> {
    use num_traits::{One, Zero};
    if depth == 0 {
        return None;
    }
    match ctx.get(expr) {
        cas_ast::Expr::Number(n) => Some(n.clone()),
        cas_ast::Expr::Neg(inner) => Some(-eval_exact_rational(ctx, *inner, depth - 1)?),
        cas_ast::Expr::Add(l, r) => Some(
            eval_exact_rational(ctx, *l, depth - 1)? + eval_exact_rational(ctx, *r, depth - 1)?,
        ),
        cas_ast::Expr::Sub(l, r) => Some(
            eval_exact_rational(ctx, *l, depth - 1)? - eval_exact_rational(ctx, *r, depth - 1)?,
        ),
        cas_ast::Expr::Mul(l, r) => Some(
            eval_exact_rational(ctx, *l, depth - 1)? * eval_exact_rational(ctx, *r, depth - 1)?,
        ),
        cas_ast::Expr::Div(l, r) => {
            let d = eval_exact_rational(ctx, *r, depth - 1)?;
            if d.is_zero() {
                return None;
            }
            Some(eval_exact_rational(ctx, *l, depth - 1)? / d)
        }
        cas_ast::Expr::Pow(base, exponent) => {
            let exp = eval_exact_rational(ctx, *exponent, depth - 1)?;
            if !exp.is_integer() {
                return None;
            }
            let e = exp.to_integer().to_i64()?;
            if e.unsigned_abs() > 64 {
                return None; // avoid blow-up
            }
            let b = eval_exact_rational(ctx, *base, depth - 1)?;
            if e == 0 {
                return Some(num_rational::BigRational::one());
            }
            let factor = if e < 0 {
                if b.is_zero() {
                    return None;
                }
                num_rational::BigRational::one() / b
            } else {
                b
            };
            let mut acc = num_rational::BigRational::one();
            for _ in 0..e.unsigned_abs() {
                acc *= &factor;
            }
            Some(acc)
        }
        _ => None,
    }
}

pub(crate) fn common_scaled_difference_has_exact_nonzero_witness(
    ctx: &mut cas_ast::Context,
    expr: cas_ast::ExprId,
) -> bool {
    use num_traits::Zero;

    let var_names: Vec<String> = cas_ast::traversal::collect_variables(ctx, expr)
        .into_iter()
        .collect();
    // Generic rationals that avoid the small-integer poles typical of these denominators.
    let samples: [(i64, i64); 5] = [(7, 2), (11, 3), (13, 5), (17, 4), (23, 6)];
    for round in 0..samples.len() {
        let mut substituted = expr;
        for (i, name) in var_names.iter().enumerate() {
            let var_node = ctx.var(name);
            let (n, d) = samples[(round + i) % samples.len()];
            let value = num_rational::BigRational::new((n + i as i64).into(), d.into());
            let value_node = ctx.add(cas_ast::Expr::Number(value));
            substituted =
                cas_ast::traversal::substitute_expr_by_id(ctx, substituted, var_node, value_node);
        }
        if let Some(value) = eval_exact_rational(ctx, substituted, 64) {
            if !value.is_zero() {
                return true; // exact non-zero value → the difference is NOT identically zero
            }
        }
        // `None` (transcendental, or a pole at this sample) cannot disprove zero — try the next.
    }
    false
}

pub(crate) fn try_build_exact_zero_common_scaled_difference_rewrite(
    ctx: &mut cas_ast::Context,
    expr: cas_ast::ExprId,
) -> Option<Rewrite> {
    // A term carrying a literal non-finite or undefined value never cancels with
    // itself: `inf - inf`, `(1/0) - (1/0)` and `undefined - undefined` are
    // indeterminate, not zero. Decline so the difference stays symbolic.
    if additive_term_is_nonfinite_or_undefined(ctx, expr) {
        return None;
    }
    // SOUNDNESS GATE: never collapse to 0 a rational expression that exactly evaluates to a non-zero
    // value at a generic point (`1/(x²−1) − 1/(x−1)` is `−x/(x²−1)`, not 0).
    if common_scaled_difference_has_exact_nonzero_witness(ctx, expr) {
        return None;
    }

    let profiling =
        crate::orchestrator_shortcut_profiler::orchestrator_shortcut_profiling_enabled();
    let expr_sample = profiling.then(|| render_expr_for_orchestrator_profile(ctx, expr));
    let profile_route = |label: &'static str| {
        if profiling {
            let _ =
                run_profiled_orchestrator_option_section(label, expr_sample.clone(), || Some(()));
        }
    };

    if let Some(rewrite) = try_build_exact_zero_same_denominator_rewrite(ctx, expr) {
        profile_route("rule.common_scale_zero.route.same_denominator");
        return Some(rewrite);
    }

    if let Some((lhs_core, rhs_core)) = extract_two_term_core_difference(ctx, expr) {
        if let Some(rewrite) =
            try_build_direct_scaled_reciprocal_half_power_shared_denominator_rewrite(
                ctx, lhs_core, rhs_core,
            )
        {
            profile_route(
                "rule.common_scale_zero.route.scaled_reciprocal_half_power_shared_denominator",
            );
            return Some(rewrite);
        }
        if let Some(rewrite) =
            try_build_direct_scaled_reciprocal_half_power_over_base_rewrite(ctx, lhs_core, rhs_core)
        {
            profile_route("rule.common_scale_zero.route.scaled_reciprocal_half_power_over_base");
            return Some(rewrite);
        }
    }

    if let Some((common_factor, lhs_core, rhs_core)) =
        extract_two_term_common_scale_difference_cores(ctx, expr)
    {
        if same_arg_sin_cos_core_pair(ctx, lhs_core, rhs_core) {
            return None;
        }
        let residual_expr = ctx.add(Expr::Sub(lhs_core, rhs_core));
        if let Some(child_rewrite) =
            try_build_repeated_trig_phase_shift_pair_zero_rewrite(ctx, residual_expr)
        {
            profile_route("rule.common_scale_zero.route.focused_phase_shift_pair");
            return Some(build_common_scale_exact_zero_rewrite(
                ctx,
                expr,
                common_factor,
                residual_expr,
                child_rewrite,
            ));
        }
        if let Some(child_rewrite) =
            try_build_exact_zero_shared_passthrough_difference_rewrite(ctx, residual_expr)
        {
            profile_route("rule.common_scale_zero.route.focused_shared_passthrough");
            return Some(build_common_scale_exact_zero_rewrite(
                ctx,
                expr,
                common_factor,
                residual_expr,
                child_rewrite,
            ));
        }
        if let Some(child_rewrite) =
            try_build_direct_tanh_exp_definition_equivalence_rewrite(ctx, lhs_core, rhs_core)
        {
            profile_route("rule.common_scale_zero.route.focused_tanh_exp");
            return Some(build_common_scale_exact_zero_rewrite(
                ctx,
                expr,
                common_factor,
                residual_expr,
                child_rewrite,
            ));
        }
        if let Some(child_rewrite) =
            try_build_direct_trig_square_equivalence_rewrite(ctx, lhs_core, rhs_core)
        {
            profile_route("rule.common_scale_zero.route.focused_trig_square");
            return Some(build_common_scale_exact_zero_rewrite(
                ctx,
                expr,
                common_factor,
                residual_expr,
                child_rewrite,
            ));
        }
        if let Some(child_rewrite) =
            try_build_direct_hyperbolic_sinh_cubic_polynomial_equivalence_rewrite(
                ctx, lhs_core, rhs_core,
            )
        {
            profile_route("rule.common_scale_zero.route.focused_sinh_cubic");
            return Some(build_common_scale_exact_zero_rewrite(
                ctx,
                expr,
                common_factor,
                residual_expr,
                child_rewrite,
            ));
        }
        if let Some(child_rewrite) =
            try_build_direct_trig_exact_quarter_phase_shift_pair_equivalence_rewrite(
                ctx, lhs_core, rhs_core,
            )
        {
            profile_route("rule.common_scale_zero.route.focused_phase_shift_quarter_pair");
            return Some(build_common_scale_exact_zero_rewrite(
                ctx,
                expr,
                common_factor,
                residual_expr,
                child_rewrite,
            ));
        }
        if let Some(child_rewrite) =
            try_build_direct_safe_hyperbolic_core_equivalence_rewrite(ctx, lhs_core, rhs_core)
        {
            profile_route("rule.common_scale_zero.route.focused_safe_hyperbolic");
            return Some(build_common_scale_exact_zero_rewrite(
                ctx,
                expr,
                common_factor,
                residual_expr,
                child_rewrite,
            ));
        }
    }

    let (common_factor, residual_expr) = extract_common_multiplicative_residual_sum(ctx, expr)?;
    if same_arg_sin_cos_additive_pair(ctx, residual_expr) {
        return None;
    }
    let residual_term_count = AddView::from_expr(ctx, residual_expr).terms.len();
    if residual_term_count == 2 {
        if let Some((lhs_core, rhs_core)) = extract_two_term_core_difference(ctx, residual_expr) {
            if let Some(rewrite_match) =
                try_find_trig_phase_shift_cancellation_match(ctx, lhs_core, rhs_core, false)
            {
                if matches!(
                    rewrite_match.mode,
                    TrigPhaseShiftCancellationMode::ShiftedToShifted
                ) {
                    profile_route(
                        "rule.common_scale_zero.route.residual_phase_shift_identity_shifted_to_shifted",
                    );
                    let child_rewrite = build_trig_phase_shift_zero_rewrite(ctx, rewrite_match);
                    return Some(build_common_scale_exact_zero_rewrite(
                        ctx,
                        expr,
                        common_factor,
                        residual_expr,
                        child_rewrite,
                    ));
                }
            }
            if let Some(child_rewrite) =
                try_build_direct_core_equivalence_rewrite(ctx, lhs_core, rhs_core)
            {
                profile_route("rule.common_scale_zero.route.residual_direct_core_equivalence");
                return Some(build_common_scale_exact_zero_rewrite(
                    ctx,
                    expr,
                    common_factor,
                    residual_expr,
                    child_rewrite,
                ));
            }
        }
    }
    if let Some(child_rewrite) =
        try_build_repeated_trig_phase_shift_pair_zero_rewrite(ctx, residual_expr)
    {
        profile_route("rule.common_scale_zero.route.residual_phase_shift_pair");
        return Some(build_common_scale_exact_zero_rewrite(
            ctx,
            expr,
            common_factor,
            residual_expr,
            child_rewrite,
        ));
    }
    if let Some(child_rewrite) =
        try_build_exact_zero_shared_passthrough_difference_rewrite(ctx, residual_expr)
    {
        profile_route("rule.common_scale_zero.route.residual_shared_passthrough");
        return Some(build_common_scale_exact_zero_rewrite(
            ctx,
            expr,
            common_factor,
            residual_expr,
            child_rewrite,
        ));
    }
    if residual_term_count <= 4 {
        if let Some(child_rewrite) =
            try_build_exact_zero_identity_rewrite_direct(ctx, residual_expr)
        {
            let zero = ctx.num(0);
            if compare_expr(ctx, child_rewrite.final_expr(), zero) == Ordering::Equal {
                profile_route("rule.common_scale_zero.route.residual_direct_identity");
                return Some(build_common_scale_exact_zero_rewrite(
                    ctx,
                    expr,
                    common_factor,
                    residual_expr,
                    child_rewrite,
                ));
            }
        }
    }
    if let Some(child_rewrite) =
        try_build_stripped_zero_log_identity_child_rewrite(ctx, residual_expr).or_else(|| {
            try_build_fast_multiterm_hyperbolic_residual_child_rewrite(ctx, residual_expr)
        })
    {
        profile_route("rule.common_scale_zero.route.residual_log_or_multiterm_hyperbolic");
        return Some(build_common_scale_exact_zero_rewrite(
            ctx,
            expr,
            common_factor,
            residual_expr,
            child_rewrite,
        ));
    }
    if let Some((lhs_core, rhs_core)) = extract_two_term_core_difference(ctx, residual_expr) {
        if let Some(child_rewrite) =
            try_build_direct_safe_hyperbolic_core_equivalence_rewrite(ctx, lhs_core, rhs_core)
        {
            profile_route("rule.common_scale_zero.route.residual_safe_hyperbolic");
            return Some(build_common_scale_exact_zero_rewrite(
                ctx,
                expr,
                common_factor,
                residual_expr,
                child_rewrite,
            ));
        }
    }

    let normalized_residual = normalize_additive_scope_expr(ctx, residual_expr);
    let child_rewrite = try_build_fast_trig_residual_identity_child_rewrite(ctx, residual_expr)
        .inspect(|_| {
            profile_route("rule.common_scale_zero.route.tail_fast_trig_raw");
        })
        .or_else(|| {
            try_build_fast_trig_residual_identity_child_rewrite(ctx, normalized_residual).inspect(
                |_| {
                    profile_route("rule.common_scale_zero.route.tail_fast_trig_normalized");
                },
            )
        })
        .or_else(|| {
            try_build_exact_zero_shared_passthrough_difference_rewrite(ctx, residual_expr).inspect(
                |_| {
                    profile_route("rule.common_scale_zero.route.tail_shared_passthrough");
                },
            )
        })
        .or_else(|| {
            try_build_fast_small_polynomial_residual_child_rewrite(ctx, residual_expr).inspect(
                |_| {
                    profile_route("rule.common_scale_zero.route.tail_fast_small_poly_raw");
                },
            )
        })
        .or_else(|| {
            try_build_fast_small_polynomial_residual_child_rewrite(ctx, normalized_residual)
                .inspect(|_| {
                    profile_route("rule.common_scale_zero.route.tail_fast_small_poly_normalized");
                })
        })
        .or_else(|| {
            try_build_two_term_core_equivalence_rewrite(ctx, residual_expr).inspect(|_| {
                profile_route("rule.common_scale_zero.route.tail_two_term_core_equivalence");
            })
        })
        .or_else(|| {
            try_build_exact_zero_identity_rewrite(ctx, residual_expr).inspect(|_| {
                profile_route("rule.common_scale_zero.route.tail_exact_zero_identity_raw");
            })
        })
        .or_else(|| {
            try_build_exact_zero_identity_rewrite(ctx, normalized_residual).inspect(|_| {
                profile_route("rule.common_scale_zero.route.tail_exact_zero_identity_normalized");
            })
        })?;
    Some(build_common_scale_exact_zero_rewrite(
        ctx,
        expr,
        common_factor,
        residual_expr,
        child_rewrite,
    ))
}

fn try_build_exact_zero_product_factor_rewrite(
    ctx: &mut cas_ast::Context,
    expr: cas_ast::ExprId,
    parent_ctx: &ParentContext,
) -> Option<Rewrite> {
    let Expr::Mul(_, _) = ctx.get(expr) else {
        return None;
    };

    let allow = cas_solver_core::undefined_risk_policy_support::allow_cancellation_with_undefined_risk_mode_flags(
        matches!(parent_ctx.domain_mode(), crate::DomainMode::Assume),
        matches!(parent_ctx.domain_mode(), crate::DomainMode::Strict),
        crate::collect::has_undefined_risk(ctx, expr),
    );
    if !allow {
        return None;
    }
    if product_has_variable_scaled_direct_trig_or_hyperbolic_additive_factor(ctx, expr) {
        return None;
    }

    let (local_factor, child_rewrite) = try_find_exact_zero_additive_factor_in_product(ctx, expr)?;
    Some(build_exact_zero_product_factor_rewrite(
        ctx,
        local_factor,
        child_rewrite,
    ))
}

fn strip_positive_one_passthrough(
    ctx: &mut cas_ast::Context,
    expr: cas_ast::ExprId,
) -> Option<cas_ast::ExprId> {
    let view = AddView::from_expr(ctx, expr);
    let mut stripped = false;
    let mut residual_terms = Vec::new();

    for (term_expr, term_sign) in view.terms {
        let is_positive_one = term_sign == Sign::Pos
            && matches!(
                ctx.get(term_expr),
                Expr::Number(n) if *n == num_rational::BigRational::from_integer(1.into())
            );

        if is_positive_one && !stripped {
            stripped = true;
            continue;
        }
        residual_terms.push((term_expr, term_sign));
    }

    if !stripped || residual_terms.is_empty() {
        return None;
    }

    Some(build_signed_sum_expr(ctx, &residual_terms))
}

#[derive(Clone, Copy)]
enum PositiveOnePassthroughProfileKind {
    Strippable,
    SinglePositiveOne,
    SingleOther,
    AddNoPositiveOne,
    AddOnlyPositiveOne,
}

#[derive(Clone, Copy)]
enum AddNoPositiveOneProfileDetail {
    NegativeOne,
    OtherNumeric,
    NonNumeric,
}

fn classify_positive_one_passthrough_profile_kind(
    ctx: &cas_ast::Context,
    expr: cas_ast::ExprId,
) -> PositiveOnePassthroughProfileKind {
    let view = AddView::from_expr(ctx, expr);
    let positive_one_count = view
        .terms
        .iter()
        .filter(|(term_expr, term_sign)| {
            *term_sign == Sign::Pos
                && matches!(
                    ctx.get(*term_expr),
                    Expr::Number(n) if *n == num_rational::BigRational::from_integer(1.into())
                )
        })
        .count();

    if view.terms.len() == 1 {
        return if positive_one_count == 1 {
            PositiveOnePassthroughProfileKind::SinglePositiveOne
        } else {
            PositiveOnePassthroughProfileKind::SingleOther
        };
    }

    if positive_one_count == 0 {
        return PositiveOnePassthroughProfileKind::AddNoPositiveOne;
    }

    if positive_one_count == view.terms.len() {
        return PositiveOnePassthroughProfileKind::AddOnlyPositiveOne;
    }

    PositiveOnePassthroughProfileKind::Strippable
}

fn classify_add_no_positive_one_profile_detail(
    ctx: &cas_ast::Context,
    expr: cas_ast::ExprId,
) -> AddNoPositiveOneProfileDetail {
    let minus_one = num_rational::BigRational::from_integer((-1).into());
    let view = AddView::from_expr(ctx, expr);
    let mut saw_other_numeric = false;

    for (term_expr, term_sign) in view.terms {
        let Expr::Number(number) = ctx.get(term_expr) else {
            continue;
        };
        let signed_number = match term_sign {
            Sign::Pos => number.clone(),
            Sign::Neg => -number.clone(),
        };

        if signed_number == minus_one {
            return AddNoPositiveOneProfileDetail::NegativeOne;
        }
        saw_other_numeric = true;
    }

    if saw_other_numeric {
        AddNoPositiveOneProfileDetail::OtherNumeric
    } else {
        AddNoPositiveOneProfileDetail::NonNumeric
    }
}

fn profile_shifted_quotient_exact_one_gate_side(
    side: &'static str,
    kind: PositiveOnePassthroughProfileKind,
    sample: Option<String>,
) {
    if !crate::orchestrator_shortcut_profiler::orchestrator_shortcut_profiling_enabled() {
        return;
    }

    let label = match (side, kind) {
        ("numerator", PositiveOnePassthroughProfileKind::Strippable) => {
            "rule.shifted_quotient.exact_one.gate.numerator.strippable"
        }
        ("numerator", PositiveOnePassthroughProfileKind::SinglePositiveOne) => {
            "rule.shifted_quotient.exact_one.gate.numerator.single_positive_one"
        }
        ("numerator", PositiveOnePassthroughProfileKind::SingleOther) => {
            "rule.shifted_quotient.exact_one.gate.numerator.single_other"
        }
        ("numerator", PositiveOnePassthroughProfileKind::AddNoPositiveOne) => {
            "rule.shifted_quotient.exact_one.gate.numerator.add_no_positive_one"
        }
        ("numerator", PositiveOnePassthroughProfileKind::AddOnlyPositiveOne) => {
            "rule.shifted_quotient.exact_one.gate.numerator.add_only_positive_one"
        }
        ("denominator", PositiveOnePassthroughProfileKind::Strippable) => {
            "rule.shifted_quotient.exact_one.gate.denominator.strippable"
        }
        ("denominator", PositiveOnePassthroughProfileKind::SinglePositiveOne) => {
            "rule.shifted_quotient.exact_one.gate.denominator.single_positive_one"
        }
        ("denominator", PositiveOnePassthroughProfileKind::SingleOther) => {
            "rule.shifted_quotient.exact_one.gate.denominator.single_other"
        }
        ("denominator", PositiveOnePassthroughProfileKind::AddNoPositiveOne) => {
            "rule.shifted_quotient.exact_one.gate.denominator.add_no_positive_one"
        }
        ("denominator", PositiveOnePassthroughProfileKind::AddOnlyPositiveOne) => {
            "rule.shifted_quotient.exact_one.gate.denominator.add_only_positive_one"
        }
        _ => unreachable!(),
    };

    let _ = run_profiled_orchestrator_option_section(label, sample, || Some(()));
}

fn profile_shifted_quotient_exact_one_gate_add_no_positive_one_detail(
    ctx: &cas_ast::Context,
    side: &'static str,
    expr: cas_ast::ExprId,
    sample: Option<String>,
) {
    if !crate::orchestrator_shortcut_profiler::orchestrator_shortcut_profiling_enabled() {
        return;
    }

    let detail = classify_add_no_positive_one_profile_detail(ctx, expr);
    let label = match (side, detail) {
        ("numerator", AddNoPositiveOneProfileDetail::NegativeOne) => {
            "rule.shifted_quotient.exact_one.gate.numerator.add_no_positive_one.negative_one"
        }
        ("numerator", AddNoPositiveOneProfileDetail::OtherNumeric) => {
            "rule.shifted_quotient.exact_one.gate.numerator.add_no_positive_one.other_numeric"
        }
        ("numerator", AddNoPositiveOneProfileDetail::NonNumeric) => {
            "rule.shifted_quotient.exact_one.gate.numerator.add_no_positive_one.non_numeric"
        }
        ("denominator", AddNoPositiveOneProfileDetail::NegativeOne) => {
            "rule.shifted_quotient.exact_one.gate.denominator.add_no_positive_one.negative_one"
        }
        ("denominator", AddNoPositiveOneProfileDetail::OtherNumeric) => {
            "rule.shifted_quotient.exact_one.gate.denominator.add_no_positive_one.other_numeric"
        }
        ("denominator", AddNoPositiveOneProfileDetail::NonNumeric) => {
            "rule.shifted_quotient.exact_one.gate.denominator.add_no_positive_one.non_numeric"
        }
        _ => unreachable!(),
    };

    let _ = run_profiled_orchestrator_option_section(label, sample, || Some(()));
}

fn build_shifted_quotient_exact_one_rewrite(
    ctx: &mut cas_ast::Context,
    numerator: cas_ast::ExprId,
    denominator: cas_ast::ExprId,
    child_rewrite: Rewrite,
) -> Rewrite {
    let mut rewrite = Rewrite::with_local(
        ctx.num(1),
        child_rewrite.description.clone(),
        numerator,
        denominator,
    )
    .requires(crate::ImplicitCondition::NonZero(denominator))
    .requires_all(child_rewrite.required_conditions.clone())
    .assume_all(child_rewrite.assumption_events.clone());

    if let Some(poly_proof) = child_rewrite.poly_proof.clone() {
        rewrite = rewrite.poly_proof(poly_proof);
    }

    rewrite.substeps = child_rewrite.substeps.clone();
    rewrite
}

fn sign_to_i64(sign: Sign) -> i64 {
    match sign {
        Sign::Pos => 1,
        Sign::Neg => -1,
    }
}

fn try_build_two_term_core_equivalence_rewrite(
    ctx: &mut cas_ast::Context,
    expr: cas_ast::ExprId,
) -> Option<Rewrite> {
    let (lhs_core, rhs_core) = extract_two_term_core_difference(ctx, expr)?;

    try_build_direct_core_equivalence_rewrite(ctx, lhs_core, rhs_core)
}

fn strip_trivial_one_product_factors_for_core_difference(
    ctx: &mut cas_ast::Context,
    expr: cas_ast::ExprId,
) -> cas_ast::ExprId {
    let factors = flatten_mul_chain(ctx, expr);
    if factors.len() <= 1 {
        return expr;
    }

    let retained: Vec<_> = factors
        .iter()
        .copied()
        .filter(|factor| !is_one_expr(ctx, *factor))
        .collect();
    if retained.len() == factors.len() {
        expr
    } else {
        build_mul_expr_from_factors(ctx, &retained)
    }
}

fn normalize_core_difference_term(
    ctx: &mut cas_ast::Context,
    term_expr: cas_ast::ExprId,
    term_sign: Sign,
) -> (cas_ast::ExprId, Sign) {
    let (term_expr, term_sign) =
        normalize_signed_add_term_for_fast_match(ctx, term_expr, term_sign);
    (
        strip_trivial_one_product_factors_for_core_difference(ctx, term_expr),
        term_sign,
    )
}

pub(crate) fn extract_two_term_core_difference(
    ctx: &mut cas_ast::Context,
    expr: cas_ast::ExprId,
) -> Option<(cas_ast::ExprId, cas_ast::ExprId)> {
    match ctx.get(expr).clone() {
        Expr::Sub(lhs, rhs) => {
            let (lhs_expr, lhs_sign) = normalize_core_difference_term(ctx, lhs, Sign::Pos);
            let (rhs_expr, rhs_sign) = normalize_core_difference_term(ctx, rhs, Sign::Pos);
            Some((
                apply_sign_to_expr(ctx, sign_to_i64(lhs_sign), lhs_expr),
                apply_sign_to_expr(ctx, sign_to_i64(rhs_sign), rhs_expr),
            ))
        }
        Expr::Add(lhs, rhs) => match ctx.get(rhs).clone() {
            Expr::Neg(inner) => {
                let (lhs_expr, lhs_sign) = normalize_core_difference_term(ctx, lhs, Sign::Pos);
                let (rhs_expr, rhs_sign) = normalize_core_difference_term(ctx, inner, Sign::Pos);
                Some((
                    apply_sign_to_expr(ctx, sign_to_i64(lhs_sign), lhs_expr),
                    apply_sign_to_expr(ctx, sign_to_i64(rhs_sign), rhs_expr),
                ))
            }
            _ => {
                let terms = AddView::from_expr(ctx, expr).terms;
                if terms.len() != 2 {
                    return None;
                }
                let (first_expr, first_sign) =
                    normalize_core_difference_term(ctx, terms[0].0, terms[0].1);
                let (second_expr, second_sign) =
                    normalize_core_difference_term(ctx, terms[1].0, terms[1].1);
                Some((
                    apply_sign_to_expr(ctx, sign_to_i64(first_sign), first_expr),
                    apply_sign_to_expr(ctx, sign_to_i64(second_sign).checked_neg()?, second_expr),
                ))
            }
        },
        _ => {
            let terms = AddView::from_expr(ctx, expr).terms;
            if terms.len() != 2 {
                return None;
            }
            let (first_expr, first_sign) =
                normalize_core_difference_term(ctx, terms[0].0, terms[0].1);
            let (second_expr, second_sign) =
                normalize_core_difference_term(ctx, terms[1].0, terms[1].1);
            Some((
                apply_sign_to_expr(ctx, sign_to_i64(first_sign), first_expr),
                apply_sign_to_expr(ctx, sign_to_i64(second_sign).checked_neg()?, second_expr),
            ))
        }
    }
}

fn try_build_two_term_direct_half_angle_square_rewrite(
    ctx: &mut cas_ast::Context,
    expr: cas_ast::ExprId,
) -> Option<Rewrite> {
    let (lhs_core, rhs_core) = extract_two_term_core_difference(ctx, expr)?;

    for (source, target) in [(lhs_core, rhs_core), (rhs_core, lhs_core)] {
        let Some(rewritten) = try_rewrite_trig_square_double_angle_half_expr(ctx, source) else {
            continue;
        };
        if exprs_match_for_cancellation(ctx, rewritten, target) {
            return Some(Rewrite::with_local(
                ctx.num(0),
                "Half-Angle Square Identity",
                lhs_core,
                rhs_core,
            ));
        }
    }

    None
}

fn build_dirichlet_nonzero_condition_expr(
    ctx: &mut cas_ast::Context,
    result: cas_math::telescoping_dirichlet::DirichletKernelResult,
) -> cas_ast::ExprId {
    let scaled_base = if result.base_multiplier == 1 {
        result.base_var
    } else {
        let multiplier = ctx.num(result.base_multiplier as i64);
        smart_mul(ctx, multiplier, result.base_var)
    };
    let two = ctx.num(2);
    let half_angle = ctx.add(Expr::Div(scaled_base, two));
    ctx.call_builtin(BuiltinFn::Sin, vec![half_angle])
}

fn try_build_exact_dirichlet_zero_scope_rewrite(
    ctx: &mut cas_ast::Context,
    expr: cas_ast::ExprId,
) -> Option<Rewrite> {
    let result = try_dirichlet_kernel_identity(ctx, expr)?;
    Some(
        Rewrite::with_local(ctx.num(0), "Dirichlet Kernel Identity", expr, ctx.num(0)).requires(
            crate::ImplicitCondition::NonZero(build_dirichlet_nonzero_condition_expr(ctx, result)),
        ),
    )
}

fn maybe_shifted_quotient_exact_zero_direct_residual_candidate(
    ctx: &cas_ast::Context,
    expr: cas_ast::ExprId,
) -> bool {
    let term_count = AddView::from_expr(ctx, expr).terms.len();
    if !(2..=4).contains(&term_count) {
        return false;
    }

    expr_contains_division_node(ctx, expr)
        || expr_contains_sqrt_or_half_power(ctx, expr)
        || expr_contains_factorial_call(ctx, expr)
        || expr_contains_any_builtin(
            ctx,
            expr,
            &[
                BuiltinFn::Sin,
                BuiltinFn::Cos,
                BuiltinFn::Tan,
                BuiltinFn::Sec,
                BuiltinFn::Csc,
                BuiltinFn::Cot,
                BuiltinFn::Asin,
                BuiltinFn::Acos,
                BuiltinFn::Atan,
                BuiltinFn::Asec,
                BuiltinFn::Acsc,
                BuiltinFn::Acot,
                BuiltinFn::Arcsin,
                BuiltinFn::Arccos,
                BuiltinFn::Arctan,
                BuiltinFn::Arcsec,
                BuiltinFn::Arccsc,
                BuiltinFn::Arccot,
                BuiltinFn::Sinh,
                BuiltinFn::Cosh,
                BuiltinFn::Tanh,
                BuiltinFn::Asinh,
                BuiltinFn::Acosh,
                BuiltinFn::Atanh,
                BuiltinFn::Ln,
                BuiltinFn::Log,
                BuiltinFn::Log2,
                BuiltinFn::Log10,
                BuiltinFn::Exp,
                BuiltinFn::Sqrt,
                BuiltinFn::Cbrt,
                BuiltinFn::Root,
                BuiltinFn::Abs,
            ],
        )
}

fn matches_shifted_quotient_exact_zero_direct_residual_trig_power_reduction_target(
    ctx: &cas_ast::Context,
    expr: cas_ast::ExprId,
) -> bool {
    let Expr::Div(numerator, denominator) = ctx.get(expr) else {
        return false;
    };

    matches!(ctx.get(*numerator), Expr::Add(_, _) | Expr::Sub(_, _))
        && matches!(ctx.get(*denominator), Expr::Number(_))
}

fn matches_shifted_quotient_exact_zero_direct_residual_trig_power_reduction_pair(
    ctx: &cas_ast::Context,
    lhs_core: cas_ast::ExprId,
    rhs_core: cas_ast::ExprId,
) -> bool {
    [(lhs_core, rhs_core), (rhs_core, lhs_core)]
        .into_iter()
        .any(|(power_side, target_side)| {
            (extract_scaled_trig_even_power_for_cancellation(ctx, power_side).is_some()
                || extract_trig_square_product_same_arg_for_cancellation(ctx, power_side).is_some())
                && matches_shifted_quotient_exact_zero_direct_residual_trig_power_reduction_target(
                    ctx,
                    target_side,
                )
        })
}

fn maybe_shifted_quotient_exact_zero_direct_residual_route_candidate(
    ctx: &mut cas_ast::Context,
    lhs_core: cas_ast::ExprId,
    rhs_core: cas_ast::ExprId,
    residual_expr: cas_ast::ExprId,
) -> bool {
    maybe_shifted_quotient_exact_zero_direct_residual_candidate(ctx, residual_expr)
        && (expr_contains_hyperbolic_builtin(ctx, residual_expr)
            || matches_shifted_quotient_exact_zero_direct_residual_trig_power_reduction_pair(
                ctx, lhs_core, rhs_core,
            ))
}

fn try_build_direct_dirichlet_core_equivalence_rewrite(
    ctx: &mut cas_ast::Context,
    lhs_core: cas_ast::ExprId,
    rhs_core: cas_ast::ExprId,
) -> Option<Rewrite> {
    let lhs_minus_rhs = ctx.add(Expr::Sub(lhs_core, rhs_core));
    if let Some(result) = try_dirichlet_kernel_identity(ctx, lhs_minus_rhs) {
        return Some(
            Rewrite::with_local(ctx.num(0), "Dirichlet Kernel Identity", lhs_core, rhs_core)
                .requires(crate::ImplicitCondition::NonZero(
                    build_dirichlet_nonzero_condition_expr(ctx, result),
                )),
        );
    }

    let rhs_minus_lhs = ctx.add(Expr::Sub(rhs_core, lhs_core));
    let result = try_dirichlet_kernel_identity(ctx, rhs_minus_lhs)?;
    Some(
        Rewrite::with_local(ctx.num(0), "Dirichlet Kernel Identity", rhs_core, lhs_core).requires(
            crate::ImplicitCondition::NonZero(build_dirichlet_nonzero_condition_expr(ctx, result)),
        ),
    )
}

fn try_build_direct_integrate_prep_exact_zero_scope_rewrite(
    ctx: &mut cas_ast::Context,
    expr: cas_ast::ExprId,
) -> Option<Rewrite> {
    let (lhs_core, rhs_core) = extract_two_term_core_difference(ctx, expr)?;
    try_build_direct_cos_product_telescoping_equivalence_rewrite(ctx, lhs_core, rhs_core)
        .or_else(|| try_build_direct_dirichlet_core_equivalence_rewrite(ctx, lhs_core, rhs_core))
}

fn maybe_integrate_prep_exact_additive_candidate(
    ctx: &mut cas_ast::Context,
    expr: cas_ast::ExprId,
) -> bool {
    if !expr_contains_division_node(ctx, expr)
        || !expr_contains_any_builtin(ctx, expr, &[BuiltinFn::Sin, BuiltinFn::Cos])
    {
        return false;
    }

    try_build_direct_integrate_prep_exact_zero_scope_rewrite(ctx, expr).is_some()
        || try_build_exact_dirichlet_zero_scope_rewrite(ctx, expr).is_some()
}

fn try_build_direct_finite_product_equivalence_rewrite(
    ctx: &mut cas_ast::Context,
    lhs_core: cas_ast::ExprId,
    rhs_core: cas_ast::ExprId,
) -> Option<Rewrite> {
    for (source, target) in [(lhs_core, rhs_core), (rhs_core, lhs_core)] {
        let Some(plan) = try_plan_finite_product_evaluation(ctx, source, 1000) else {
            continue;
        };

        if exprs_match_for_cancellation(ctx, plan.candidate, target)
            || exprs_match_after_default_simplify(ctx, plan.candidate, target)
        {
            let description = match plan.kind {
                ProductEvaluationKind::Telescoping
                | ProductEvaluationKind::FactorizedTelescoping => "Finite Telescoping Product",
                ProductEvaluationKind::ProductOfFirstIntegers
                | ProductEvaluationKind::ProductOfPowers
                | ProductEvaluationKind::ProductOfConstant => "Finite Product Closed Form",
                ProductEvaluationKind::FiniteDirect { .. } => "Finite Product",
                ProductEvaluationKind::DivergentInfinite => "Divergent Infinite Product",
            };
            return Some(Rewrite::with_local(ctx.num(0), description, source, target));
        }
    }

    None
}

fn finite_sum_evaluation_description(kind: &SumEvaluationKind) -> &'static str {
    match kind {
        SumEvaluationKind::Telescoping => "Finite Telescoping Sum",
        SumEvaluationKind::SumOfFirstIntegers
        | SumEvaluationKind::SumOfSquares
        | SumEvaluationKind::SumOfCubes
        | SumEvaluationKind::SumOfConstant
        | SumEvaluationKind::GeometricPower
        | SumEvaluationKind::PolynomialLinearity => "Finite Sum Closed Form",
        SumEvaluationKind::FiniteDirect { .. } => "Finite Sum",
        SumEvaluationKind::DivergentInfinite => "Divergent Infinite Series",
        SumEvaluationKind::ConvergentInfinite => "Convergent Geometric Series",
        SumEvaluationKind::UndefinedPole => "Undefined (pole in range)",
    }
}

fn try_plan_scaled_finite_sum_evaluation(
    ctx: &mut cas_ast::Context,
    expr: cas_ast::ExprId,
) -> Option<(cas_ast::ExprId, SumEvaluationPlan)> {
    if let Some(plan) = try_plan_finite_sum_evaluation(ctx, expr, 1000) {
        let one = ctx.num(1);
        return Some((one, plan));
    }

    let view = MulView::from_expr(ctx, expr);
    if view.factors.len() < 2 {
        return None;
    }

    for (index, factor) in view.factors.iter().copied().enumerate() {
        let Some(plan) = try_plan_finite_sum_evaluation(ctx, factor, 1000) else {
            continue;
        };

        let scale_factors: Vec<_> = view
            .factors
            .iter()
            .copied()
            .enumerate()
            .filter_map(|(factor_index, factor)| (factor_index != index).then_some(factor))
            .collect();
        return Some((build_mul_expr_from_factors(ctx, &scale_factors), plan));
    }

    None
}

fn two_term_fraction_sum_parts_for_finite_evaluation_match(
    ctx: &mut cas_ast::Context,
    expr: cas_ast::ExprId,
) -> Option<(cas_ast::ExprId, cas_ast::ExprId)> {
    let expr = strip_trivial_one_product_factors_for_core_difference(ctx, expr);
    let terms = AddView::from_expr(ctx, expr).terms;
    if terms.len() != 2 {
        return None;
    }

    let (first_num, first_den) = as_div(ctx, terms[0].0)?;
    let (second_num, second_den) = as_div(ctx, terms[1].0)?;
    let first_cross = smart_mul(ctx, first_num, second_den);
    let second_cross = smart_mul(ctx, second_num, first_den);
    let numerator_terms = [(first_cross, terms[0].1), (second_cross, terms[1].1)];
    let numerator = build_signed_sum_expr(ctx, &numerator_terms);
    let denominator = smart_mul(ctx, first_den, second_den);
    Some((numerator, denominator))
}

fn finite_evaluation_fraction_parts_for_match(
    ctx: &mut cas_ast::Context,
    expr: cas_ast::ExprId,
) -> Option<(cas_ast::ExprId, cas_ast::ExprId)> {
    let mut numerator_factors = Vec::new();
    let mut denominator_factors = Vec::new();

    for factor in flatten_mul_chain(ctx, expr) {
        if is_one_expr(ctx, factor) {
            continue;
        }
        if let Some((num, den)) = as_div(ctx, factor) {
            if !is_one_expr(ctx, num) {
                numerator_factors.push(num);
            }
            denominator_factors.push(den);
        } else {
            numerator_factors.push(factor);
        }
    }

    if denominator_factors.is_empty() {
        return None;
    }

    let denominator = build_mul_expr_from_factors(ctx, &denominator_factors);
    for (index, factor) in numerator_factors.iter().copied().enumerate() {
        let Some((inner_num, inner_den)) =
            two_term_fraction_sum_parts_for_finite_evaluation_match(ctx, factor)
        else {
            continue;
        };

        let adjusted_numerator_factors: Vec<_> = numerator_factors
            .iter()
            .copied()
            .enumerate()
            .filter_map(|(factor_index, factor)| (factor_index != index).then_some(factor))
            .chain(std::iter::once(inner_num))
            .collect();
        let numerator = build_mul_expr_from_factors(ctx, &adjusted_numerator_factors);
        return Some((numerator, smart_mul(ctx, denominator, inner_den)));
    }

    let numerator = build_mul_expr_from_factors(ctx, &numerator_factors);
    if let Some((inner_num, inner_den)) =
        two_term_fraction_sum_parts_for_finite_evaluation_match(ctx, numerator)
    {
        return Some((inner_num, smart_mul(ctx, denominator, inner_den)));
    }

    Some((numerator, denominator))
}

fn finite_evaluation_fraction_parts_match(
    ctx: &mut cas_ast::Context,
    lhs: cas_ast::ExprId,
    rhs: cas_ast::ExprId,
) -> bool {
    let Some((lhs_num, lhs_den)) = finite_evaluation_fraction_parts_for_match(ctx, lhs) else {
        return false;
    };
    let Some((rhs_num, rhs_den)) = finite_evaluation_fraction_parts_for_match(ctx, rhs) else {
        return false;
    };

    let lhs_cross = smart_mul(ctx, lhs_num, rhs_den);
    let rhs_cross = smart_mul(ctx, rhs_num, lhs_den);
    exprs_match_for_cancellation(ctx, lhs_cross, rhs_cross)
        || poly_eq(ctx, lhs_cross, rhs_cross)
        || exprs_match_after_default_simplify(ctx, lhs_cross, rhs_cross)
}

fn finite_evaluation_candidate_matches_target(
    ctx: &mut cas_ast::Context,
    candidate: cas_ast::ExprId,
    target: cas_ast::ExprId,
) -> bool {
    if exprs_match_for_cancellation(ctx, candidate, target)
        || exprs_match_after_default_simplify(ctx, candidate, target)
    {
        return true;
    }

    if finite_evaluation_fraction_parts_match(ctx, candidate, target) {
        return true;
    }

    let residual = ctx.add(Expr::Sub(candidate, target));
    try_build_exact_zero_identity_rewrite_direct_impl(ctx, residual, false).is_some()
        || try_build_exact_zero_common_scaled_difference_rewrite(ctx, residual).is_some()
}

fn try_build_direct_finite_sum_equivalence_rewrite(
    ctx: &mut cas_ast::Context,
    lhs_core: cas_ast::ExprId,
    rhs_core: cas_ast::ExprId,
) -> Option<Rewrite> {
    for (source, target) in [(lhs_core, rhs_core), (rhs_core, lhs_core)] {
        let Some((scale, plan)) = try_plan_scaled_finite_sum_evaluation(ctx, source) else {
            continue;
        };
        let candidate = smart_mul(ctx, scale, plan.candidate);

        if finite_evaluation_candidate_matches_target(ctx, candidate, target) {
            let description = finite_sum_evaluation_description(&plan.kind);
            return Some(Rewrite::with_local(ctx.num(0), description, source, target));
        }
    }

    None
}

fn try_build_direct_cos_product_telescoping_equivalence_rewrite(
    ctx: &mut cas_ast::Context,
    lhs_core: cas_ast::ExprId,
    rhs_core: cas_ast::ExprId,
) -> Option<Rewrite> {
    for (source, target) in [(lhs_core, rhs_core), (rhs_core, lhs_core)] {
        let Some(rewrite_match) = crate::try_rewrite_cos_product_telescoping_expr(ctx, source)
        else {
            continue;
        };

        let rewritten_normalized =
            cas_math::canonical_forms::normalize_core(ctx, rewrite_match.rewritten);
        let target_normalized = cas_math::canonical_forms::normalize_core(ctx, target);
        if exprs_match_for_cancellation(ctx, rewrite_match.rewritten, target)
            || exprs_equal_up_to_fraction_parts_for_cancellation(
                ctx,
                rewrite_match.rewritten,
                target,
            )
            || compare_expr(ctx, rewritten_normalized, target_normalized) == Ordering::Equal
            || exprs_equal_up_to_fraction_parts_for_cancellation(
                ctx,
                rewritten_normalized,
                target_normalized,
            )
        {
            return Some(
                Rewrite::with_local(
                    ctx.num(0),
                    "Apply Morrie's law",
                    source,
                    rewrite_match.rewritten,
                )
                .requires(crate::ImplicitCondition::NonZero(
                    rewrite_match.assume_nonzero_expr,
                )),
            );
        }
    }

    None
}

pub(crate) fn try_build_direct_trig_power_reduction_equivalence_rewrite(
    ctx: &mut cas_ast::Context,
    lhs_core: cas_ast::ExprId,
    rhs_core: cas_ast::ExprId,
) -> Option<Rewrite> {
    let matches_trig_power_reduction_form =
        |ctx: &mut cas_ast::Context, lhs: cas_ast::ExprId, rhs: cas_ast::ExprId| {
            if compare_expr(ctx, lhs, rhs) == Ordering::Equal
                || exprs_equal_up_to_add_term_order(ctx, lhs, rhs)
                || exprs_equal_up_to_add_term_multiset_for_cancellation(ctx, lhs, rhs)
                || exprs_equal_up_to_mul_factor_order_and_sign(ctx, lhs, rhs)
                || exprs_equal_up_to_same_denominator(ctx, lhs, rhs)
            {
                return true;
            }

            let lhs_normalized = cas_math::canonical_forms::normalize_core(ctx, lhs);
            let rhs_normalized = cas_math::canonical_forms::normalize_core(ctx, rhs);
            compare_expr(ctx, lhs_normalized, rhs_normalized) == Ordering::Equal
                || exprs_equal_up_to_add_term_order(ctx, lhs_normalized, rhs_normalized)
                || exprs_equal_up_to_add_term_multiset_for_cancellation(
                    ctx,
                    lhs_normalized,
                    rhs_normalized,
                )
                || exprs_equal_up_to_mul_factor_order_and_sign(ctx, lhs_normalized, rhs_normalized)
                || exprs_equal_up_to_same_denominator(ctx, lhs_normalized, rhs_normalized)
        };

    if let Some(rewritten) = try_rewrite_trig_power_reduction_expr_for_cancellation(ctx, lhs_core) {
        if matches_trig_power_reduction_form(ctx, rewritten, rhs_core) {
            return Some(Rewrite::with_local(
                ctx.num(0),
                "Power Reduction Identity",
                lhs_core,
                rhs_core,
            ));
        }
    }
    if let Some(rewritten) = try_rewrite_trig_power_reduction_expr_for_cancellation(ctx, rhs_core) {
        if matches_trig_power_reduction_form(ctx, rewritten, lhs_core) {
            return Some(Rewrite::with_local(
                ctx.num(0),
                "Power Reduction Identity",
                lhs_core,
                rhs_core,
            ));
        }
    }
    None
}

